  empBadge: { fontSize: '10px', background: 'rgba(99,102,241,0.2)', color: '#a5b4fc', borderRadius: '4px', padding: '3px 8px', display: 'inline-block', letterSpacing: '1px', fontFamily: "'Space Mono', monospace" },
